module top_module(
  input [3:0] in,
  output reg [3:0] out
);always @(*)
  wire [3:0] _tap_in = in & {4{1'b1}};

  begin
    if (in >= 0 && in <= 7) // Range 0 to 7
      out = in << 1;
    else if (in >= 8 && in <= 15) // Range 8 to 15
      out = in >> 1;
    else // Outside range 0 to 15
      out = 0;
  end

endmodule
